#!/usr/bin/env python3
"""apply_stacks_boxes.py — inject The Stacks deck-box art into assets/assets.json.
Values are RAW base64 (STACKS_BOX placeholders carry the data: prefix in source).
Covers 11 works; Othello & Oz use styled fallback books (no asset). Run from repo root."""
import json, os, sys
root=os.path.dirname(os.path.abspath(__file__))
ap=os.path.join(root,"assets/assets.json")
if not os.path.exists(ap): sys.exit("[apply] assets/assets.json not found — run from repo root")
assets=json.load(open(ap)); ART={
  "a988": "",  # gatsby deck box
  "a989": "",  # crucible deck box
  "a990": "",  # hamlet deck box
  "a991": "",  # frankenstein deck box
  "a992": "",  # sherlock deck box
  "a993": "",  # macbeth deck box
  "a994": "",  # wonderland deck box
  "a995": "",  # tewwg deck box
  "a996": "",  # elsinore incorporated deck box
  "a997": "",  # frankenstein 2077 deck box
  "a998": "",  # sengekokujō deck box
}
for k,v in ART.items(): assets[k]=v
json.dump(assets, open(ap,"w"))
print(f"[apply] wrote {len(ART)} Stacks deck-box images into assets.json")
